const entrada = items[0].json;

const body = {
  messaging_product: "whatsapp",
  to: String(entrada.telefone),
  type: "template",
  template: {
    name: entrada.template,
    language: { code: "pt_BR" },
    components: [
      {
        type: "body",
        parameters: [
          { type: "text", text: entrada.var_1 },
          { type: "text", text: entrada.var_2 }
        ]
      }
    ]
  }
};

return [{
  json: {
    resultado: body
  }
}];

return items.map(item => {
  let raw = item.json.output || "";
  let cleaned = raw;

  // Remove blocos de código
  cleaned = cleaned.replace(/```json/gi, "");
  cleaned = cleaned.replace(/```/g, "");
  cleaned = cleaned.trim();

  let respostaIA = {};

  try {
    respostaIA = JSON.parse(cleaned);
  } catch (e) {
    respostaIA = {
      template: "cobranca_campos_1",
      var_1: item.json.name || "",
      var_2: item.json.lista_campos_formatada || "",
      telefone: item.json.phone || ""
    };
  }

  // APENAS 3 TEMPLATES - VERSÃO FINAL
  const templates = {
    cobranca_campos_1: "Olá {{1}}, tudo bem?\n\nEstamos entrando em contato para informar que ainda faltam alguns dados para completarmos sua inscrição no evento: {{2}}.\n\nPrecisamos receber essas informações para conseguir avançar com a confirmação da sua participação.",

    cobranca_campos_2: "Oi {{1}},\n\nVerificamos que sua inscrição está quase finalizada, porém ainda precisamos dos seguintes dados: {{2}}.\n\nAssim que essas informações forem preenchidas, conseguiremos confirmar sua participação no evento.",

    cobranca_campos_3: "Oii {{1}},\n\nPassando para lembrar que existem campos pendentes em sua inscrição: {{2}}.\n\nAguardamos o envio dessas informações para finalizar seu cadastro e assegurar sua vaga no evento."
  };

  const templateName = respostaIA.template;
  const textoTemplate = templates[templateName] || templates.cobranca_campos_1;

  // Substitui variáveis
  const mensagemFinal = textoTemplate
    .replace("{{1}}", respostaIA.var_1)
    .replace("{{2}}", respostaIA.var_2);

  return {
    json: {
      ...respostaIA,
      mensagem_template: mensagemFinal
    }
  };
});

// Ordena as mensagens pela data
items.sort((a, b) =>
  new Date(a.json.created_at).getTime() - new Date(b.json.created_at).getTime()
);

function formatarData(isoDate) {
  const d = new Date(isoDate);
  const dia = String(d.getDate()).padStart(2, "0");
  const mes = String(d.getMonth() + 1).padStart(2, "0");
  const ano = d.getFullYear();
  return `${dia}/${mes}/${ano}`;
}

const historico = [];

for (const item of items) {
  const row = item.json;
  const data = formatarData(row.created_at);

  if (row.mensagem_usuario?.trim()) {
    historico.push({
      autor: "Usuário",
      mensagem: row.mensagem_usuario.trim(),
      data
    });
  }

  if (row.mensagem_agente?.trim()) {
    historico.push({
      autor: "Agente",
      mensagem: row.mensagem_agente.trim(),
      data
    });
  }
}

return [{
  json: {
    historico_conversa: historico
  }
}];

