// Percorre todos os itens para evitar erro de "item is not defined"
for (const item of items) {

  const qtdObrigatorios = item.json.qtd_obrigatorios;
  const txtObrigatorios = item.json.txt_obrigatorios || ""; // Garante que não é null
  const qtdOpcionais = item.json.qtd_opcionais;
  const txtOpcionais = item.json.txt_opcionais || ""; // Garante que não é null

  let msg_template = "";

  // 1. Processa OBRIGATÓRIOS
  if (qtdObrigatorios > 0) {
    // O comando .replace(/\n/g, ", ") troca todas as quebras de linha por vírgula
    let listaLimpa = txtObrigatorios.replace(/\n/g, ", ");
    msg_template += "🚨 Obrigatórios: " + listaLimpa + ". ";
  }

  // 2. Processa OPCIONAIS
  if (qtdOpcionais > 0) {
    // Adiciona um espaço antes se já tiver texto dos obrigatórios
    if (msg_template.length > 0) msg_template += " "; 

    let listaLimpa = txtOpcionais.replace(/\n/g, ", ");
    msg_template += "Opcionais: " + listaLimpa + ".";
  }

  // Salva na variável 'mensagem_final'
  item.json.mensagem_final = msg_template;
}

return items;
